INSERT INTO `flow_templates` (`template_id`, `name`, `description`, `category`, `pattern`, `difficulty`, `tags`, `source_url`, `source_author`, `is_official`, `flow_data`) VALUES

-- Template 1: Simple Agent
('simple-agent', 'Simple Agent', 'A single agent with built-in tools. The most basic Strands pattern — one agent, one model, connected to input and output.', 'single-agent', NULL, 'beginner', '["starter", "basic", "hello-world"]', 'https://strandsagents.com/docs/user-guide/quickstart/python/', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":80,"y":200},"data":{"label":"User Input"}},{"id":"agent_1","type":"agent","position":{"x":400,"y":180},"data":{"label":"Assistant","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a helpful AI assistant.","temperature":0.7,"maxTokens":4000}},{"id":"tool_1","type":"tool","position":{"x":400,"y":50},"data":{"label":"Calculator","toolType":"built-in","toolName":"calculator"}},{"id":"output_1","type":"output","position":{"x":720,"y":200},"data":{"label":"Response"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_1","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"tool_1","target":"agent_1","sourceHandle":"tool-output","targetHandle":"tools"},{"id":"e3","source":"agent_1","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":false}'),

-- Template 2: Orchestrator with Sub-Agents
('orchestrator-sub-agents', 'Orchestrator with Sub-Agents', 'Supervisor agent that delegates tasks to specialized sub-agents. The Agents-as-Tools pattern — the orchestrator decides which specialist to call based on the query.', 'agents-as-tools', NULL, 'intermediate', '["multi-agent", "hierarchical", "supervisor", "delegation"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/agents-as-tools/', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":80,"y":250},"data":{"label":"User Query"}},{"id":"orchestrator_1","type":"orchestrator-agent","position":{"x":400,"y":230},"data":{"label":"Orchestrator","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are an assistant that routes requests to specialized agents. Select the most appropriate sub-agent based on the query.","temperature":0.7,"maxTokens":4000}},{"id":"agent_research","type":"agent","position":{"x":700,"y":100},"data":{"label":"Research Agent","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a research specialist. Find and summarize information.","temperature":0.7,"maxTokens":4000}},{"id":"agent_writer","type":"agent","position":{"x":700,"y":350},"data":{"label":"Writing Agent","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a writing specialist. Create clear, engaging content.","temperature":0.7,"maxTokens":4000}},{"id":"output_1","type":"output","position":{"x":400,"y":450},"data":{"label":"Response"}}],"edges":[{"id":"e1","source":"input_1","target":"orchestrator_1","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"orchestrator_1","target":"agent_research","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e3","source":"orchestrator_1","target":"agent_writer","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e4","source":"orchestrator_1","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":false}'),

-- Template 3: Static Swarm
('static-swarm', 'Autonomous Swarm Team', 'Team of specialized agents that hand off tasks to each other autonomously. No central controller — agents decide the path collaboratively.', 'swarm', NULL, 'intermediate', '["multi-agent", "autonomous", "handoff", "collaboration"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/swarm/', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":80,"y":200},"data":{"label":"User Request"}},{"id":"swarm_1","type":"swarm","position":{"x":400,"y":180},"data":{"label":"Support Team","maxHandoffs":20,"maxIterations":20,"executionTimeout":900,"nodeTimeout":300}},{"id":"agent_general","type":"agent","position":{"x":700,"y":80},"data":{"label":"General Support","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a general customer support agent. Route to specialists when needed.","temperature":0.7,"maxTokens":4000}},{"id":"agent_billing","type":"agent","position":{"x":700,"y":230},"data":{"label":"Billing Specialist","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You specialize in billing, payments, and subscription issues.","temperature":0.7,"maxTokens":4000}},{"id":"agent_technical","type":"agent","position":{"x":700,"y":380},"data":{"label":"Technical Support","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You specialize in technical troubleshooting and debugging.","temperature":0.7,"maxTokens":4000}},{"id":"output_1","type":"output","position":{"x":400,"y":450},"data":{"label":"Resolution"}}],"edges":[{"id":"e1","source":"input_1","target":"swarm_1","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"swarm_1","target":"agent_general","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e3","source":"swarm_1","target":"agent_billing","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e4","source":"swarm_1","target":"agent_technical","sourceHandle":"sub-agents","targetHandle":"orchestrator-input"},{"id":"e5","source":"swarm_1","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":false}'),

-- Template 4: Sequential Graph Pipeline
('graph-sequential', 'Sequential Pipeline (Graph)', 'Linear graph flow: Research → Analysis → Review → Report. Each agent depends on the previous one''s output.', 'graph', 'sequential', 'intermediate', '["graph", "pipeline", "sequential", "DAG"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/graph/#1-sequential-pipeline', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":80,"y":200},"data":{"label":"Task"}},{"id":"agent_research","type":"agent","position":{"x":350,"y":180},"data":{"label":"Researcher","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a research specialist. Gather and summarize information.","temperature":0.7,"maxTokens":4000}},{"id":"agent_analyst","type":"agent","position":{"x":650,"y":180},"data":{"label":"Analyst","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a data analysis specialist. Analyze the research findings.","temperature":0.7,"maxTokens":4000}},{"id":"agent_reviewer","type":"agent","position":{"x":950,"y":180},"data":{"label":"Reviewer","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a quality reviewer. Check for accuracy and completeness.","temperature":0.7,"maxTokens":4000}},{"id":"agent_writer","type":"agent","position":{"x":1250,"y":180},"data":{"label":"Report Writer","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are a report writing specialist. Create clear, comprehensive reports.","temperature":0.7,"maxTokens":4000}},{"id":"output_1","type":"output","position":{"x":1550,"y":200},"data":{"label":"Final Report"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_research","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"agent_research","target":"agent_analyst","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e3","source":"agent_analyst","target":"agent_reviewer","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e4","source":"agent_reviewer","target":"agent_writer","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e5","source":"agent_writer","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":true}'),

-- Template 5: Parallel Graph (Fan-out/Fan-in)
('graph-parallel', 'Parallel Processing (Graph)', 'Fan-out/Fan-in pattern: Coordinator distributes to 3 parallel workers, then Aggregator combines results.', 'graph', 'parallel', 'advanced', '["graph", "parallel", "fan-out", "fan-in", "aggregation"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/graph/#2-parallel-processing-with-aggregation', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":80,"y":250},"data":{"label":"Task"}},{"id":"agent_coord","type":"agent","position":{"x":350,"y":230},"data":{"label":"Coordinator","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You coordinate tasks and distribute work to parallel workers.","temperature":0.7,"maxTokens":4000}},{"id":"agent_w1","type":"agent","position":{"x":700,"y":80},"data":{"label":"Worker 1","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are Worker 1. Process your portion of the task.","temperature":0.7,"maxTokens":4000}},{"id":"agent_w2","type":"agent","position":{"x":700,"y":250},"data":{"label":"Worker 2","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are Worker 2. Process your portion of the task.","temperature":0.7,"maxTokens":4000}},{"id":"agent_w3","type":"agent","position":{"x":700,"y":420},"data":{"label":"Worker 3","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You are Worker 3. Process your portion of the task.","temperature":0.7,"maxTokens":4000}},{"id":"agent_agg","type":"agent","position":{"x":1050,"y":250},"data":{"label":"Aggregator","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You aggregate and synthesize results from multiple workers into a unified output.","temperature":0.7,"maxTokens":4000}},{"id":"output_1","type":"output","position":{"x":1350,"y":260},"data":{"label":"Combined Result"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_coord","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"agent_coord","target":"agent_w1","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e3","source":"agent_coord","target":"agent_w2","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e4","source":"agent_coord","target":"agent_w3","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e5","source":"agent_w1","target":"agent_agg","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e6","source":"agent_w2","target":"agent_agg","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e7","source":"agent_w3","target":"agent_agg","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e8","source":"agent_agg","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":true}'),

-- Template 6: Feedback Loop Graph (Cyclic)
('graph-feedback-loop', 'Feedback Loop (Graph)', 'Cyclic graph: Writer drafts → Reviewer evaluates → loops back until approved. Demonstrates controlled cycles with max execution limits.', 'graph', 'feedback-loop', 'advanced', '["graph", "cyclic", "feedback", "iterative", "refinement"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/graph/#4-feedback-loop', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":80,"y":200},"data":{"label":"Writing Task"}},{"id":"agent_writer","type":"agent","position":{"x":400,"y":180},"data":{"label":"Draft Writer","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You write drafts based on the task. Incorporate feedback from reviews.","temperature":0.8,"maxTokens":4000}},{"id":"agent_reviewer","type":"agent","position":{"x":750,"y":180},"data":{"label":"Reviewer","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You review drafts for quality. Respond with APPROVED if good, or REVISION NEEDED with specific feedback.","temperature":0.3,"maxTokens":4000}},{"id":"agent_publisher","type":"agent","position":{"x":1100,"y":180},"data":{"label":"Publisher","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You format and publish the approved content.","temperature":0.5,"maxTokens":4000}},{"id":"output_1","type":"output","position":{"x":1400,"y":200},"data":{"label":"Published"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_writer","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"agent_writer","target":"agent_reviewer","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e3","source":"agent_reviewer","target":"agent_writer","sourceHandle":"output","targetHandle":"user-input","animated":true,"style":{"stroke":"#ef4444","strokeDasharray":"5,5"}},{"id":"e4","source":"agent_reviewer","target":"agent_publisher","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e5","source":"agent_publisher","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":true}'),

-- Template 7: Workflow DAG Pipeline  
('workflow-pipeline', 'Task Workflow Pipeline', 'DAG-based workflow with explicit task dependencies and parallel execution. Uses the strands_tools workflow tool for deterministic task management.', 'workflow', NULL, 'intermediate', '["workflow", "DAG", "tasks", "dependencies", "parallel"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/workflow/', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":80,"y":200},"data":{"label":"User Request"}},{"id":"workflow_1","type":"workflow","position":{"x":400,"y":160},"data":{"label":"Data Analysis Workflow","workflowId":"data_analysis","tasks":[{"taskId":"data_extraction","description":"Extract key data from the input","systemPrompt":"You extract and structure data from reports.","dependencies":[],"priority":5},{"taskId":"trend_analysis","description":"Analyze trends in the extracted data","systemPrompt":"You identify trends in data.","dependencies":["data_extraction"],"priority":3},{"taskId":"report_generation","description":"Generate comprehensive report","systemPrompt":"You create clear analysis reports.","dependencies":["trend_analysis"],"priority":2}]}},{"id":"output_1","type":"output","position":{"x":750,"y":200},"data":{"label":"Analysis Report"}}],"edges":[{"id":"e1","source":"input_1","target":"workflow_1","sourceHandle":"output","targetHandle":"input"},{"id":"e2","source":"workflow_1","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":false}'),

-- Template 8: A2A Distributed Architecture
('a2a-distributed', 'Distributed A2A Architecture', 'Local agents orchestrate with remote A2A agents for distributed processing. Data prep locally, ML and NLP on remote specialized servers.', 'a2a', NULL, 'advanced', '["a2a", "distributed", "remote", "cross-platform", "microservices"]', 'https://strandsagents.com/docs/user-guide/concepts/multi-agent/agent-to-agent/', 'Strands SDK', TRUE, '{"nodes":[{"id":"input_1","type":"input","position":{"x":80,"y":250},"data":{"label":"Analysis Request"}},{"id":"agent_prep","type":"agent","position":{"x":350,"y":230},"data":{"label":"Data Prep (Local)","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You prepare data for analysis, cleaning and formatting as needed.","temperature":0.5,"maxTokens":4000}},{"id":"a2a_ml","type":"a2a-agent","position":{"x":700,"y":120},"data":{"label":"ML Analysis (Remote)","endpoint":"http://ml-service:9000","timeout":600}},{"id":"a2a_nlp","type":"a2a-agent","position":{"x":700,"y":350},"data":{"label":"NLP Processing (Remote)","endpoint":"http://nlp-service:9000","timeout":300}},{"id":"agent_report","type":"agent","position":{"x":1050,"y":230},"data":{"label":"Report Writer (Local)","modelProvider":"AWS Bedrock","modelId":"us.anthropic.claude-3-7-sonnet-20250219-v1:0","modelName":"Claude 3.7 Sonnet","systemPrompt":"You synthesize analysis results into clear, actionable reports.","temperature":0.7,"maxTokens":4000}},{"id":"output_1","type":"output","position":{"x":1350,"y":250},"data":{"label":"Final Report"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_prep","sourceHandle":"output","targetHandle":"user-input"},{"id":"e2","source":"agent_prep","target":"a2a_ml","sourceHandle":"output","targetHandle":"input","animated":true},{"id":"e3","source":"agent_prep","target":"a2a_nlp","sourceHandle":"output","targetHandle":"input","animated":true},{"id":"e4","source":"a2a_ml","target":"agent_report","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e5","source":"a2a_nlp","target":"agent_report","sourceHandle":"output","targetHandle":"user-input","animated":true},{"id":"e6","source":"agent_report","target":"output_1","sourceHandle":"output","targetHandle":"input"}],"graphMode":true}');
